'use strict'

/**
 * Module dependencies.
 * @private
 */

var EventEmitter = require('events').EventEmitter

/**
 * Module exports.
 * @public
 */

module.exports = {
  eventListenerCount: eventListenerCount,
  getNodeMajorVersion: getNodeMajorVersion,
  hasEmitWarning: hasEmitWarning
}

/**
 * Get the count of listeners for a given event on an EventEmitter.
 * Provides compatibility layer for different Node.js versions.
 *
 * @param {EventEmitter} emitter
 * @param {string} type
 * @returns {number}
 * @public
 */
function eventListenerCount(emitter, type) {
  // Use native Node.js function if available (Node.js >= 4.0)
  if (typeof emitter.listenerCount === 'function') {
    return emitter.listenerCount(type)
  }

  // Use EventEmitter.listenerCount if available (Node.js >= 0.12, < 4.0)
  if (EventEmitter.listenerCount) {
    return EventEmitter.listenerCount(emitter, type)
  }

  // Fallback for older Node.js versions
  var listeners = emitter.listeners(type)
  return listeners ? listeners.length : 0
}

/**
 * Get the major version of the Node.js runtime.
 * Used for feature detection and compatibility handling.
 *
 * @returns {number}
 * @public
 */
function getNodeMajorVersion() {
  // Process.version format: 'v' + major + '.' + minor + '.' + patch
  var match = process.version.match(/^v([^.]+)\./)
  
  return match ? Number(match[1]) : 0
}

/**
 * Determine if the Node.js runtime supports process.emitWarning.
 * This feature was added in Node.js v6.0.0.
 *
 * @returns {boolean}
 * @public
 */
function hasEmitWarning() {
  return typeof process.emitWarning === 'function'
}